                    msg_timestamp = parsed_date.timestamp()
                except:
                    msg_timestamp = 0.0
            else:
                msg_timestamp = 0.0

            # 只返回新邮件（上次检查之后的新邮件）
            if msg_timestamp <= last_check_time:
                continue

            # 获取邮件头部信息
            status, msg_data = mail.fetch(e_id, "(BODY.PEEK[HEADER])")
            if status != "OK":
                continue

            msg = email.message_from_bytes(msg_data[0][1])

            # 解码主题
            subject, encoding = decode_header(msg["Subject"])[0] if msg["Subject"] else ("(无主题)", None)
            if isinstance(subject, bytes):
                subject = subject.decode(encoding or "utf-8", errors="replace")

            # 发件人
            from_addr = msg.get("From", "(未知)")

            # 邮件 ID
