                "hint": "Please check credentials and ensure IMAP is enabled."
            }],
            "next_cursor": last_cursor or datetime.now(timezone.utc).isoformat()
        }

    return {
        "events": new_emails,
        "next_cursor": latest_dt.isoformat()
    }
